#include<cstdio>
#include<iostream>
#include<algorithm>
using namespace std;

const int N = 1e6 + 5;
bool flag[N];
int depth[N], max_depth = 0;
struct Node
{
	int lch, rch;
}tree[N];

void dfs(int x)
{
	if(x == 0) return;
	depth[tree[x].lch] = depth[tree[x].rch] = depth[x] + 1;
	max_depth = max(max_depth, depth[tree[x].lch]);
	dfs(tree[x].lch);
	dfs(tree[x].rch);
}

int main(){
	int n;
	cin >> n;
	depth[1] = 0;
	for(int i = 1; i <= n; i++)
	{
		cin >> tree[i].lch >> tree[i].rch;
		flag[tree[i].lch] = flag[tree[i].rch] = 1;
	}
	int root;
	for(int i = 1; i <= n; i++)
		if(!flag[i]) root = i;
	dfs(root);
	cout << max_depth;
	return 0;
}
